-- ===== Flowtime Migration aus protokolle.json + audit.json =====
-- Quelle: Drive-Backup vom 2026-05-07

BEGIN;

DO $mig$ DECLARE
  v_shop_id uuid; v_user_id uuid; v_proto_id uuid;
  v_s1_id uuid; v_s2_id uuid;
BEGIN
  SELECT id INTO v_shop_id FROM public.shops WHERE kurz = 'MGR';
  SELECT id INTO v_user_id FROM public.profiles WHERE name = 'Mehdi';
    VALUES (v_shop_id, '2026-05-06', v_user_id, '2026-05-06T13:00:48.920Z')
    ON CONFLICT (shop_id, datum) DO UPDATE SET erstellt_von = EXCLUDED.erstellt_von
    RETURNING id INTO v_proto_id;
  -- Schicht 1
  DECLARE v_s1_mit uuid; BEGIN
    SELECT id INTO v_s1_mit FROM public.profiles WHERE name = 'Mehdi';
      protokoll_id, schicht_nr, mitarbeiter_id, zeit_von, zeit_bis,
      kassenstart, kassenstart_manuell, kassenstart_grund, kassenabrechnung,
      beleg_storage_path, guthaben_kundenkarte, offene_auszahlungen, kassenist, kommentar)
    VALUES (
      v_proto_id, 1, v_s1_mit,
      '10:00',
      '17:00',
      1635.2,
      true,
      NULL,
      844.51,
      'data:image/jpeg;base64,',
      NULL,
      NULL,
      2599.85,
      NULL
    )
    ON CONFLICT (protokoll_id, schicht_nr) DO UPDATE SET
      mitarbeiter_id = EXCLUDED.mitarbeiter_id,
      zeit_von = EXCLUDED.zeit_von, zeit_bis = EXCLUDED.zeit_bis,
      kassenstart = EXCLUDED.kassenstart,
      kassenstart_manuell = EXCLUDED.kassenstart_manuell,
      kassenstart_grund = EXCLUDED.kassenstart_grund,
      kassenabrechnung = EXCLUDED.kassenabrechnung,
      beleg_storage_path = EXCLUDED.beleg_storage_path,
      guthaben_kundenkarte = EXCLUDED.guthaben_kundenkarte,
      offene_auszahlungen = EXCLUDED.offene_auszahlungen,
      kassenist = EXCLUDED.kassenist,
      kommentar = EXCLUDED.kommentar
    RETURNING id INTO v_s1_id;
      VALUES (v_s1_id, 'einlage', 'Melik', 20, 0);
      VALUES (v_s1_id, 'einlage', 'Petro', 200, 1);
      VALUES (v_s1_id, 'entnahme', 'Recai', 100, 0);
  END;
  -- Schicht 2
  DECLARE v_s2_mit uuid; BEGIN
    SELECT id INTO v_s2_mit FROM public.profiles WHERE name = 'Oskar';
      protokoll_id, schicht_nr, mitarbeiter_id, zeit_von, zeit_bis,
      kassenstart, kassenstart_manuell, kassenstart_grund, kassenabrechnung,
      beleg_storage_path, guthaben_kundenkarte, offene_auszahlungen, kassenist, kommentar)
    VALUES (
      v_proto_id, 2, v_s2_mit,
      '17:00',
      '23:00',
      2599.85,
      false,
      NULL,
      2149.1,
      'data:image/jpeg;base64,',
      NULL,
      NULL,
      4648.4,
      'Zwei Abrechnungen (2943) und (2942)'
    )
    ON CONFLICT (protokoll_id, schicht_nr) DO UPDATE SET
      mitarbeiter_id = EXCLUDED.mitarbeiter_id,
      zeit_von = EXCLUDED.zeit_von, zeit_bis = EXCLUDED.zeit_bis,
      kassenstart = EXCLUDED.kassenstart,
      kassenstart_manuell = EXCLUDED.kassenstart_manuell,
      kassenstart_grund = EXCLUDED.kassenstart_grund,
      kassenabrechnung = EXCLUDED.kassenabrechnung,
      beleg_storage_path = EXCLUDED.beleg_storage_path,
      guthaben_kundenkarte = EXCLUDED.guthaben_kundenkarte,
      offene_auszahlungen = EXCLUDED.offene_auszahlungen,
      kassenist = EXCLUDED.kassenist,
      kommentar = EXCLUDED.kommentar
    RETURNING id INTO v_s2_id;
      VALUES (v_s2_id, 'entnahme', 'Besim', 50, 0);
      VALUES (v_s2_id, 'entnahme', 'Volkan', 20, 1);
      VALUES (v_s2_id, 'entnahme', 'Vanessa', 20, 2);
      VALUES (v_s2_id, 'entnahme', 'Murat', 10, 3);
  END;
END $mig$ LANGUAGE plpgsql;

DO $mig$ DECLARE
  v_shop_id uuid; v_user_id uuid; v_proto_id uuid;
  v_s1_id uuid; v_s2_id uuid;
BEGIN
  SELECT id INTO v_shop_id FROM public.shops WHERE kurz = 'MGR';
  SELECT id INTO v_user_id FROM public.profiles WHERE name = 'Mehdi';
    VALUES (v_shop_id, '2026-05-07', v_user_id, '2026-05-07T07:57:04.699Z')
